let cache;
try { cache = JSON.parse($input.item.json.stdout || '{}'); } catch { cache = {}; }
const mtd = cache.mtd || { revenue: 0, orders: 0, burn: 0 };
const ratio = mtd.burn > 0 ? (mtd.revenue / mtd.burn) : null;
const kills = cache.killSkuCandidates || [];
const killLine = kills.length === 0 ? 'no kill-SKU candidates' : `${kills.length} kill candidates: ${kills.slice(0,3).map(k => k.sku).join(', ')}`;
const ratioLine = ratio === null ? 'burn not set' : `${ratio.toFixed(2)}× above the line (rev $${mtd.revenue.toFixed(0)} / burn $${mtd.burn.toFixed(0)})`;
return [{ json: {
  priority: 'P2',
  source: 'weekly-pnl-digest',
  message: `Weekly P&L:\n• ${ratioLine}\n• ${mtd.orders} MTD orders\n• ${killLine}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/money'
} }];
